1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOWUP_RATE = 0.15;
9	const COMPONENT_BASE = 25;
10	const COMPONENT_BLOCK_BASE = 60;
11	const BLOCK_SIZE = 3;
12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
15	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	
19	const BASE_PREMIUM: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	};
25	
26	const INSURANCE_VALUE: Record<string, number> = {
27	  sword: 1000,
28	  amulet: 600,
29	  staff: 800,
30	  potion: 400,
31	  rune: 250,
32	  moonstone: 250,
33	};
34	
35	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
36	type Customer = { yearsWithMHPCO: number };
37	type Damage = { itemType: string; amount: number };
38	type Incident = { cause: string; damages: Damage[] };
39	type QuoteStep = { op: "quote"; items: Item[] };
40	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
41	type Step = QuoteStep | ClaimStep;
42	type Scenario = { customer: Customer; steps: Step[] };
43	
44	type QuoteResult = { premium: number };
45	type ClaimResult = { payout: number; remainingCap: number };
46	type Result = QuoteResult | ClaimResult;
47	
48	type Policy = { items: Item[]; cap: number; remainingCap: number };
49	
50	const isComponent = (item: Item) => COMPONENT_TYPES.has(item.type);
51	
52	const baseForCount = (count: number): number =>
53	  count === BLOCK_SIZE ? COMPONENT_BLOCK_BASE : count * COMPONENT_BASE;
54	
55	const countByType = (items: Item[]): Record<string, number> => {
56	  const counts: Record<string, number> = {};
57	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
58	  return counts;
59	};
60	
61	const componentBase = (items: Item[]): number =>
62	  Object.values(countByType(items)).reduce((sum, count) => sum + baseForCount(count), 0);
63	
64	const itemBase = (item: Item): number => BASE_PREMIUM[item.type];
65	
66	const itemSurcharge = (item: Item): number => {
67	  const base = itemBase(item);
68	  let surcharge = 0;
69	  if (item.cursed) surcharge += base * CURSE_RATE;
70	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) surcharge += base * HIGH_ENCHANTMENT_RATE;
71	  return surcharge;
72	};
73	
74	const quotePremium = (items: Item[], customer: Customer, contractIndex: number): number => {
75	  const components = items.filter(isComponent);
76	  const mains = items.filter((i) => !isComponent(i));
77	  const policyBase = mains.reduce((sum, item) => sum + itemBase(item), 0) + componentBase(components);
78	  const itemSurcharges = mains.reduce((sum, item) => sum + itemSurcharge(item), 0);
79	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
80	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_RATE : 0;
81	  const followUp = contractIndex > 0 ? policyBase * FOLLOWUP_RATE : 0;
82	  return Math.ceil(policyBase + itemSurcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
83	};
84	
85	const policyInsuranceSum = (items: Item[]): number =>
86	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
87	
88	const damagePayout = (damage: Damage, item: Item | undefined): number => {
89	  const enchantment = item?.enchantment ?? 0;
90	  const reimbursableFraction = enchantment >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
91	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
92	    : 1;
93	  return Math.max(0, damage.amount * reimbursableFraction - DEDUCTIBLE);
94	};
95	
96	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
97	  const grossPayout = incident.damages.reduce((sum, d) => {
98	    const item = policy.items.find((i) => i.type === d.itemType);
99	    return sum + damagePayout(d, item);
100	  }, 0);
101	  const payout = Math.floor(Math.min(grossPayout, policy.remainingCap));
102	  policy.remainingCap -= payout;
103	  return { payout, remainingCap: policy.remainingCap };
104	};
105	
106	export const runScenario = (scenario: Scenario): { results: Result[] } => {
107	  const policies: Record<number, Policy> = {};
108	  const results: Result[] = scenario.steps.map((step, index) => {
109	    if (step.op === "quote") {
110	      const sum = policyInsuranceSum(step.items);
111	      policies[index] = { items: step.items, cap: sum * CAP_MULTIPLIER, remainingCap: sum * CAP_MULTIPLIER };
112	      return { premium: quotePremium(step.items, scenario.customer, index) };
113	    }
114	    return processClaim(policies[step.policy], step.incident);
115	  });
116	  return { results };
117	};
